          "name": "disk",
          "parent": 1
        },
        {
          "id": 3,
          "name": "io",
          "parent": 2
        },
        {
          "id": 4,
          "name": "operations",
          "parent": 2
        },
        {
          "id": 5,
          "name": "time",
          "parent": 2
        },
        {
          "id": 8,
          "name": "cpu",
          "parent": 1
        },
        {
          "id": 9,
          "name": "time",
          "parent": 8
        },
        {
          "id": 10,
          "name": "utilization",
          "parent": 8
        },
        {
          "id": 11,
          "name": "network",
          "parent": 1
        },
        {
          "id": 12,
          "name": "dropped_packets",
          "parent": 11
        },
        {
          "id": 13,
          "name": "errors",
          "parent": 11
        },
        {
          "id": 14,
          "name": "io",
          "parent": 11
        },
        {
          "id": 15,
          "name": "packets",
          "parent": 11
        },
        {
          "id": 16,
          "name": "memory",
          "parent": 1
        },
        {
          "id": 17,
          "name": "usage",
          "parent": 16
        },
        {
          "id": 18,
          "name": "utilization",
          "parent": 16
        },
        {
          "id": 23,
          "name": "connections",
          "parent": 11
        },
        {
          "id": 24,
          "name": "swap",
          "parent": 1
        },
        {
          "id": 25,
          "name": "usage",
          "parent": 24
        },
        {
          "id": 26,
          "name": "utilization",
          "parent": 24
        },
        {
          "id": 30,
          "name": "thread_count",
          "parent": 1
        }
      ]
