    {
      "name": "tree",
      "source": "raw-data",
      "transform": [
        {
          "type": "stratify",
          "key": "id",
          "parentKey": "parent"
        },
        {
          "type": "lookup",
          "from": "raw-data",
          "key": "id",
          "fields": [
            "parent"
          ],
          "as": [
            "parentData"
          ]
        },
        {
          "type": "tree",
          "method": {
            "signal": "layout"
          },
          "size": [
            {
              "signal": "height"
            },
            {
              "signal": "width - 100"
            }
          ],
