{"title":"system-services-metrics-tree-map (copy 1)","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "padding": 5,
  "background": "white",
  "title": {"text": "Service Operations Map", "anchor": "start"},
  "signals": [
    {
      "name": "labels",
      "value": true,
      "bind": {"input": "checkbox"}
    },
    {
      "name": "layout",
      "value": "tidy",
      "bind": {"input": "radio", "options": ["tidy", "cluster"]}
    },
    {
      "name": "links",
      "value": "diagonal",
      "bind": {
        "input": "select",
        "options": ["line", "curve", "diagonal", "orthogonal"]
      }
    },
    {
      "name": "separation",
      "value": false,
      "bind": {"input": "checkbox"}
    },
    {
      "name": "zoom",
      "value": 1,
      "on": [
        {
          "events": {
            "type": "wheel",
            "source": "view",
            "consume": true,
            "preventDefault": true
          },
          "update": "clamp(zoom * pow(1.001, -event.deltaY * pow(16, event.deltaMode)), 0.4, 4)"
        }
      ]
    },
    {
      "name": "panAnchor",
      "value": null,
      "on": [
        {
          "events": {"type": "pointerdown", "source": "view", "consume": true},
          "update": "{x:x(), y:y(), panX:panX, panY:panY}"
        },
        {
          "events": {"type": "pointerup", "source": "window", "consume": true},
          "update": "null"
        }
      ]
    },
    {
      "name": "panX",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "pointermove",
            "source": "window",
            "consume": true,
            "between": [
              {"type": "pointerdown", "source": "view", "consume": true},
              {"type": "pointerup", "source": "window", "consume": true}
            ]
          },
          "update": "panAnchor ? panAnchor.panX + (x() - panAnchor.x) : panX"
        }
      ]
    },
    {
      "name": "panY",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "pointermove",
            "source": "window",
            "consume": true,
            "between": [
              {"type": "pointerdown", "source": "view", "consume": true},
              {"type": "pointerup", "source": "window", "consume": true}
            ]
          },
          "update": "panAnchor ? panAnchor.panY + (y() - panAnchor.y) : panY"
        }
      ]
    }
  ],
  "data": [
    {
      "name": "source_0",
      "url": {
        "index": "jaeger-service-*",
        "body": {
          "size": 5000,
          "query": {
            "bool": {
              "must": [
                "%dashboard_context-must_clause%"
              ],
              "should": [
                {
                  "range": {
                    "startTime": {
                      "%timefilter%": true
                    }
                  }
                },
                {
                  "range": {
                    "time": {
                      "%timefilter%": true
                    }
                  }
                }
              ],
              "minimum_should_match": 0,
              "must_not": [
                "%dashboard_context-must_not_clause%"
              ],
              "filter": [
                "%dashboard_context-filter_clause%"
              ]
            }
          }
        }
      },
      "format": {
        "property": "hits.hits"
      },
      "transform": [
        {
          "type": "project",
          "fields": ["_source.serviceName", "_source.operationName"],
          "as": ["serviceName", "operationName"]
        },
        {
          "type": "filter",
          "expr": "isValid(datum.serviceName) && isValid(datum.operationName)"
        }
      ]
    },
    {
      "name": "service_nodes",
      "source": "source_0",
      "transform": [
        {
          "type": "aggregate",
          "groupby": ["serviceName"]
        },
        {
          "type": "formula",
          "as": "id",
          "expr": "'service:' + datum.serviceName"
        },
        {
          "type": "formula",
          "as": "name",
          "expr": "datum.serviceName"
        },
        {
          "type": "formula",
          "as": "parent",
          "expr": "'root'"
        }
      ]
    },
    {
      "name": "operation_nodes",
      "source": "source_0",
      "transform": [
        {
          "type": "aggregate",
          "groupby": ["serviceName", "operationName"]
        },
        {
          "type": "formula",
          "as": "id",
          "expr": "'op:' + datum.serviceName + ':' + datum.operationName"
        },
        {
          "type": "formula",
          "as": "name",
          "expr": "datum.operationName"
        },
        {
          "type": "formula",
          "as": "parent",
          "expr": "'service:' + datum.serviceName"
        }
      ]
    },
    {
      "name": "root_nodes",
      "values": [
        {"id": "root", "name": ""}
      ]
    },
    {
      "name": "nodes",
      "source": ["root_nodes", "service_nodes", "operation_nodes"]
    },
    {
      "name": "tree",
      "source": "nodes",
      "transform": [
        {
          "type": "stratify",
          "key": "id",
          "parentKey": "parent"
        },
        {
          "type": "lookup",
          "from": "nodes",
          "key": "id",
          "fields": ["parent"],
          "as": ["parentData"]
        },
        {
          "type": "tree",
          "method": {"signal": "layout"},
          "size": [{"signal": "height"}, {"signal": "width - 50"}],
          "separation": {"signal": "separation"},
          "as": ["y", "x", "depth", "children"]
        }
      ]
    },
    {
      "name": "links",
      "source": "tree",
      "transform": [
        {"type": "treelinks"},
        {
          "type": "linkpath",
          "orient": "horizontal",
          "shape": {"signal": "links"}
        },
        {
          "type": "formula",
          "as": "parentName",
          "expr": "datum.source.name"
        }
      ]
    },
    {
      "name": "links_no_root",
      "source": "links",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.source.id !== 'root'"
        }
      ]
    },
    {
      "name": "tree_no_root",
      "source": "tree",
      "transform": [
        {
          "type": "filter",
          "expr": "datum.id !== 'root'"
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "parentColor",
      "type": "ordinal",
      "domain": {"data": "tree", "field": "parent"},
      "range": {"scheme": "category20"}
    }
  ],
  "marks": [
    {
      "type": "group",
      "encode": {
        "update": {
          "x": {"signal": "panX"},
          "y": {"signal": "panY"},
          "scaleX": {"signal": "zoom"},
          "scaleY": {"signal": "zoom"}
        }
      },
      "marks": [
        {
          "type": "path",
          "from": {"data": "links_no_root"},
          "encode": {
            "update": {
              "path": {"field": "path"},
              "stroke": {"value": "#ccc"}
            }
          }
        },
        {
          "type": "symbol",
          "from": {"data": "tree_no_root"},
          "encode": {
            "enter": {
              "size": {"value": 200},
              "stroke": {"value": "#fff"}
            },
            "update": {
              "x": {"field": "x"},
              "y": {"field": "y"},
              "fill": {"scale": "parentColor", "field": "parent"},
              "size": {"signal": "datum.children ? 150 : 200"},
              "shape": {"signal": "datum.children ? 'circle' : 'square'"},
              "strokeWidth": {"value": 1.5}
            },
            "hover": {
              "size": {"value": 400},
              "tooltip": {
                "signal": "datum.parentData ? {'Name': datum.name, 'Parent Group': datum.parentData.name} : {'Name': datum.name}"
              }
            }
          }
        },
        {
          "type": "text",
          "from": {"data": "tree_no_root"},
          "encode": {
            "enter": {
              "fill": {"value": "black"},
              "text": {"field": "name"},
              "fontSize": {"value": 12},
              "baseline": {"value": "middle"}
            },
            "update": {
              "x": {"field": "x"},
              "y": {"field": "y"},
              "dx": {"signal": "datum.children ? -7 : 7"},
              "align": {"signal": "datum.children ? 'right' : 'left'"},
              "opacity": {"signal": "labels ? 1 : 0"}
            }
          }
        }
      ]
    }
  ]
}
"}}

