{"title":"system-services-metrics-tree-map (copy)","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "padding": 5,
  "background": "white",
  "title": {"text": "Service Dependencies Map", "anchor": "start"},
  "signals": [
    {
      "name": "labels",
      "value": true
    },
    {
      "name": "centerX",
      "update": "width / 2 - (data('node_extent')[0].minX + data('node_extent')[0].maxX) / 2"
    },
    {
      "name": "centerY",
      "update": "height / 2 - (data('node_extent')[0].minY + data('node_extent')[0].maxY) / 2"
    },
    {
      "name": "zoom",
      "value": 1,
      "on": [
        {
          "events": {"type": "wheel", "source": "view", "consume": true},
          "update": "clamp(zoom * pow(1.001, -event.deltaY * pow(16, event.deltaMode)), 0.4, 4)"
        }
      ]
    },
    {
      "name": "panAnchor",
      "value": null,
      "on": [
        {
          "events": {"type": "pointerdown", "source": "view"},
          "update": "{x:x(), y:y(), panX:panX, panY:panY}"
        },
        {
          "events": {"type": "pointerup", "source": "window"},
          "update": "null"
        }
      ]
    },
    {
      "name": "panX",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "pointermove",
            "source": "window",
            "between": [
              {"type": "pointerdown", "source": "view"},
              {"type": "pointerup", "source": "window"}
            ]
          },
          "update": "panAnchor ? panAnchor.panX + (x() - panAnchor.x) : panX"
        }
      ]
    },
    {
      "name": "panY",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "pointermove",
            "source": "window",
            "between": [
              {"type": "pointerdown", "source": "view"},
              {"type": "pointerup", "source": "window"}
            ]
          },
          "update": "panAnchor ? panAnchor.panY + (y() - panAnchor.y) : panY"
        }
      ]
    }
  ],
  "data": [
    {
      "name": "source_0",
      "url": {
        "index": "jaeger-dependencies-*",
        "body": {
          "size": 5000,
          "fields": [
            "dependencies.parent",
            "dependencies.child",
            "dependencies.callCount"
          ],
          "_source": true,
          "stored_fields": ["*"],
          "query": {
            "bool": {
              "must": [
                "%dashboard_context-must_clause%"
              ],
              "should": [
                {
                  "range": {
                    "startTime": {
                      "%timefilter%": true
                    }
                  }
                },
                {
                  "range": {
                    "time": {
                      "%timefilter%": true
                    }
                  }
                },
                {
                  "range": {
                    "timestamp": {
                      "%timefilter%": true
                    }
                  }
                }
              ],
              "minimum_should_match": 0,
              "must_not": [
                "%dashboard_context-must_not_clause%"
              ],
              "filter": [
                "%dashboard_context-filter_clause%"
              ]
            }
          }
        }
      },
      "format": {
        "property": "hits.hits"
      },
      "transform": [
        {
          "type": "formula",
          "as": "parents",
          "expr": "datum._source && datum._source.dependencies && isArray(datum._source.dependencies.parent) ? datum._source.dependencies.parent : (datum.fields && datum.fields['dependencies.parent'] ? datum.fields['dependencies.parent'] : [])"
        },
        {
          "type": "formula",
          "as": "children",
          "expr": "datum._source && datum._source.dependencies && isArray(datum._source.dependencies.child) ? datum._source.dependencies.child : (datum.fields && datum.fields['dependencies.child'] ? datum.fields['dependencies.child'] : [])"
        },
        {
          "type": "formula",
          "as": "callCounts",
          "expr": "datum._source && datum._source.dependencies && isArray(datum._source.dependencies.callCount) ? datum._source.dependencies.callCount : (datum.fields && datum.fields['dependencies.callCount'] ? datum.fields['dependencies.callCount'] : [])"
        },
        {
          "type": "flatten",
          "fields": ["parents", "children", "callCounts"],
          "as": ["parent", "child", "callCount"]
        },
        {
          "type": "filter",
          "expr": "isValid(datum.parent) && isValid(datum.child)"
        }
      ]
    },
    {
      "name": "links",
      "source": "source_0",
      "transform": [
        {
          "type": "aggregate",
          "groupby": ["parent", "child"],
          "ops": ["sum"],
          "fields": ["callCount"],
          "as": ["callCount"]
        },
        {
          "type": "formula",
          "as": "source",
          "expr": "datum.parent"
        },
        {
          "type": "formula",
          "as": "target",
          "expr": "datum.child"
        }
      ]
    },
    {
      "name": "nodes_raw",
      "source": "links",
      "transform": [
        {
          "type": "fold",
          "fields": ["source", "target"],
          "as": ["role", "name"]
        },
        {
          "type": "aggregate",
          "groupby": ["name"]
        },
        {
          "type": "formula",
          "as": "id",
          "expr": "datum.name"
        }
      ]
    },
    {
      "name": "nodes",
      "source": "nodes_raw",
      "transform": [
        {
          "type": "force",
          "static": true,
          "iterations": 400,
          "forces": [
            {
              "force": "center",
              "x": {"signal": "width / 2"},
              "y": {"signal": "height / 2"}
            },
            {
              "force": "collide",
              "radius": 28
            },
            {
              "force": "nbody",
              "strength": -50
            },
            {
              "force": "link",
              "links": "links",
              "distance": 120,
              "id": "id"
            }
          ]
        }
      ]
    },
    {
      "name": "node_extent",
      "source": "nodes",
      "transform": [
        {
          "type": "aggregate",
          "fields": ["x", "x", "y", "y"],
          "ops": ["min", "max", "min", "max"],
          "as": ["minX", "maxX", "minY", "maxY"]
        }
      ]
    }
  ],
  "marks": [
    {
      "type": "rule",
      "from": {"data": "links"},
      "encode": {
        "update": {
          "x": {"signal": "(datum.source.x + centerX) * zoom + panX"},
          "y": {"signal": "(datum.source.y + centerY) * zoom + panY"},
          "x2": {"signal": "(datum.target.x + centerX) * zoom + panX"},
          "y2": {"signal": "(datum.target.y + centerY) * zoom + panY"},
          "stroke": {"value": "#c9c9c9"},
          "strokeWidth": {"signal": "max(1, 1 * zoom)"}
        },
        "hover": {
          "stroke": {"value": "#8c8c8c"},
          "strokeWidth": {"value": 2}
        }
      }
    },
    {
      "type": "symbol",
      "from": {"data": "nodes"},
      "encode": {
        "enter": {
          "size": {"value": 200},
          "fill": {"value": "#4c9bff"},
          "stroke": {"value": "#111"},
          "strokeWidth": {"value": 1.5}
        },
        "update": {
          "x": {"signal": "(datum.x + centerX) * zoom + panX"},
          "y": {"signal": "(datum.y + centerY) * zoom + panY"}
        },
        "hover": {
          "size": {"value": 320},
          "tooltip": {
            "signal": "{'Service': datum.name}"
          }
        }
      }
    },
    {
      "type": "text",
      "from": {"data": "nodes"},
      "encode": {
        "enter": {
          "fill": {"value": "black"},
          "text": {"field": "name"},
          "fontSize": {"value": 12},
          "baseline": {"value": "middle"}
        },
        "update": {
          "x": {"signal": "(datum.x + centerX) * zoom + panX"},
          "y": {"signal": "(datum.y + centerY) * zoom + panY"},
          "dx": {"signal": "8 * zoom"},
          "align": {"value": "left"},
          "opacity": {"signal": "labels ? 1 : 0"}
        }
      }
    }
  ]
}
"}}

{"title":"Service Dependency Map","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "padding": {
    "left": 0,
    "right": 0,
    "top": 0,
    "bottom": 0
  },
  "autosize": "pad",
  "background": "#f4f7ff",
  "signals": [
    {
      "name": "xrange",
      "update": "[0, width]"
    },
    {
      "name": "yrange",
      "update": "[height, 0]"
    },
    {
      "name": "xext",
      "update": "[0, width]"
    },
    {
      "name": "yext",
      "update": "[height, 0]"
    },
    {
      "name": "down",
      "value": null,
      "on": [
        {
          "events": "mouseup,touchend",
          "update": "null"
        },
        {
          "events": "mousedown, touchstart",
          "update": "xy()"
        },
        {
          "events": "symbol:mousedown, symbol:touchstart",
          "update": "null"
        }
      ]
    },
    {
      "name": "xcur",
      "value": null,
      "on": [
        {
          "events": "mousedown, touchstart, touchend",
          "update": "xdom"
        }
      ]
    },
    {
      "name": "ycur",
      "value": null,
      "on": [
        {
          "events": "mousedown, touchstart, touchend",
          "update": "ydom"
        }
      ]
    },
    {
      "name": "delta",
      "value": [
        0,
        0
      ],
      "on": [
        {
          "events": [
            {
              "source": "window",
              "type": "mousemove",
              "consume": true,
              "between": [
                {
                  "type": "mousedown"
                },
                {
                  "source": "window",
                  "type": "mouseup"
                }
              ]
            },
            {
              "type": "touchmove",
              "consume": true,
              "filter": "event.touches.length === 1"
            }
          ],
          "update": "down ? [down[0]-x(), y()-down[1]] : [0,0]"
        }
      ]
    },
    {
      "name": "anchor",
      "value": [
        0,
        0
      ],
      "on": [
        {
          "events": "wheel",
          "update": "[invert('xscale', x()), invert('yscale', y())]"
        },
        {
          "events": {
            "type": "touchstart",
            "filter": "event.touches.length===2"
          },
          "update": "[(xdom[0] + xdom[1]) / 2, (ydom[0] + ydom[1]) / 2]"
        }
      ]
    },
    {
      "name": "zoom",
      "value": 1,
      "on": [
        {
          "events": "wheel!",
          "force": true,
          "update": "pow(1.001, event.deltaY * pow(16, event.deltaMode))"
        },
        {
          "events": {
            "signal": "dist2"
          },
          "force": true,
          "update": "dist1 / dist2"
        },
        {
          "events": [
            {
              "source": "view",
              "type": "dblclick"
            }
          ],
          "update": "1"
        }
      ]
    },
    {
      "name": "dist1",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "touchstart",
            "filter": "event.touches.length===2"
          },
          "update": "pinchDistance(event)"
        },
        {
          "events": {
            "signal": "dist2"
          },
          "update": "dist2"
        }
      ]
    },
    {
      "name": "dist2",
      "value": 0,
      "on": [
        {
          "events": {
            "type": "touchmove",
            "consume": true,
            "filter": "event.touches.length===2"
          },
          "update": "pinchDistance(event)"
        }
      ]
    },
    {
      "name": "xdom",
      "update": "xext",
      "on": [
        {
          "events": {
            "signal": "delta"
          },
          "update": "[xcur[0] + span(xcur) * delta[0] / width, xcur[1] + span(xcur) * delta[0] / width]"
        },
        {
          "events": {
            "signal": "zoom"
          },
          "update": "[anchor[0] + (xdom[0] - anchor[0]) * zoom, anchor[0] + (xdom[1] - anchor[0]) * zoom]"
        },
        {
          "events": [
            {
              "source": "view",
              "type": "dblclick"
            }
          ],
          "update": "xrange"
        }
      ]
    },
    {
      "name": "ydom",
      "update": "yext",
      "on": [
        {
          "events": {
            "signal": "delta"
          },
          "update": "[ycur[0] + span(ycur) * delta[1] / height, ycur[1] + span(ycur) * delta[1] / height]"
        },
        {
          "events": {
            "signal": "zoom"
          },
          "update": "[anchor[1] + (ydom[0] - anchor[1]) * zoom, anchor[1] + (ydom[1] - anchor[1]) * zoom]"
        },
        {
          "events": [
            {
              "source": "view",
              "type": "dblclick"
            }
          ],
          "update": "yrange"
        }
      ]
    },
    {
      "name": "size",
      "update": "clamp(20 / span(xdom), 1, 1000)"
    },
    {
      "name": "cx",
      "update": "width / 2",
      "on": [
        {
          "events": "[symbol:mousedown, window:mouseup] > window:mousemove",
          "update": " cx==width/2?cx+0.001:width/2"
        }
      ]
    },
    {
      "name": "cy",
      "update": "height / 2"
    },
    {
      "name": "nodeRadiusKey",
      "description": "q=increase size, a=decrease size",
      "value": 8,
      "on": [
        {
          "events": "window:keypress",
          "update": "event.key=='a'&&nodeRadiusKey>1?nodeRadiusKey-1:event.key=='q'?nodeRadiusKey+1:nodeRadiusKey"
        }
      ]
    },
    {
      "name": "nodeRadius",
      "value": 8,
      "bind": {
        "input": "range",
        "min": 1,
        "max": 50,
        "step": 1
      },
      "on": [
        {
          "events": {
            "signal": "nodeRadiusKey"
          },
          "update": "nodeRadiusKey"
        }
      ]
    },
    {
      "name": "nodeCharge",
      "value": -30,
      "bind": {
        "input": "range",
        "min": -100,
        "max": 10,
        "step": 1
      }
    },
    {
      "name": "linkDistance",
      "value": 30,
      "bind": {
        "input": "range",
        "min": 5,
        "max": 300,
        "step": 1
      }
    },
    {
      "description": "State variable for active node fix status.",
      "name": "fix",
      "value": false,
      "on": [
        {
          "events": "symbol:mouseout[!event.buttons], window:mouseup",
          "update": "false"
        },
        {
          "events": "symbol:mouseover",
          "update": "fix || true",
          "force": true
        },
        {
          "events": "[symbol:mousedown, window:mouseup] > window:mousemove!",
          "update": "xy()",
          "force": true
        }
      ]
    },
    {
      "description": "Graph node most recently interacted with.",
      "name": "node",
      "value": null,
      "on": [
        {
          "events": "symbol:mouseover",
          "update": "fix === true ? datum.index : node"
        }
      ]
    },
    {
      "name": "nodeHover",
      "value": {
        "id": null,
        "connections": []
      },
      "on": [
        {
          "events": "symbol:mouseover",
          "update": "{'id':datum.index, 'connections':split(datum.sources+','+datum.targets,',')}"
        },
        {
          "events": "symbol:mouseout",
          "update": "{'id':null, 'connections':[]}"
        }
      ]
    },
    {
      "description": "Flag to restart Force simulation upon data changes.",
      "name": "restart",
      "value": false,
      "on": [
        {
          "events": {
            "signal": "fix"
          },
          "update": "fix && fix.length"
        }
      ]
    }
  ],
  "data": [
    {
      "name": "node-data-raw",
      "url": {
        "%context%": "true",
        "index": "otel-v1-apm-span-*",
        "body": {
          "size": 0,
          "aggs": {
            "services": {
              "terms": {
                "field": "serviceName",
                "size": 10000
              }
            }
          }
        }
      },
      "format": {
        "type": "json",
        "property": "aggregations.services.buckets"
      },
      "transform": [
        {
          "type": "formula",
          "expr": "'http://localhost:5601/app/dashboards#/view/single-service-correlated-dashboard-1_0_0_ID?_a=(description:%27%27,filters:!((%27$state%27:(store:appState),meta:(alias:!n,disabled:!f,key:serviceName,negate:!f,params:(query:' + datum.serviceName + '),type:phrase),query:(match_phrase:(serviceName:' + datum.name + ')))),fullScreenMode:!f,options:(hidePanelTitles:!f,useMargins:!t),query:(language:kuery,query:%27%27),timeRestore:!f,title:single-service-correlated-dashboard,viewMode:view)'",
          "as": "link"
        },
        {
          "type": "formula",
          "expr": "datum.doc_count",
          "as": "traceCounts"
        },
        {
          "type": "formula",
          "expr": "datum.key",
          "as": "name"
        },
        {
          "type": "formula",
          "expr": "datum.key",
          "as": "group"
        }
      ]
    },
    {
      "name": "link-data-raw",
      "url": {
        "%context%": "true",
        "index": "otel-v1-apm-service-map*",
        "body": {
          "size": 0,
          "aggs": {
            "services": {
              "terms": {
                "size": 10000,
                "field": "serviceName"
              },
              "aggs": {
                "target": {
                  "terms": {
                    "size": 10000,
                    "field": "destination.domain"
                  }
                }
              }
            }
          }
        }
      },
      "format": {
        "property": "aggregations.services.buckets"
      },
      "transform": [
        {
          "type": "flatten",
          "fields": [
            "target.buckets"
          ],
          "as": [
            "targetBucket"
          ]
        },
        {
          "type": "formula",
          "expr": "datum.doc_count",
          "as": "value"
        },
        {
          "type": "formula",
          "expr": "datum.key",
          "as": "source"
        },
        {
          "type": "formula",
          "expr": "datum.targetBucket.key",
          "as": "target"
        },
        {
          "type": "lookup",
          "from": "node-data-raw",
          "key": "name",
          "fields": [
            "source",
            "target"
          ],
          "as": [
            "sourceNode",
            "targetNode"
          ]
        },
        {
          "type": "filter",
          "expr": "datum.sourceNode !== null && datum.targetNode !== null"
        }
      ]
    },
    {
      "name": "link-data",
      "source": "link-data-raw"
    },
    {
      "name": "source-connections",
      "source": "link-data-raw",
      "transform": [
        {
          "type": "aggregate",
          "groupby": [
            "source"
          ],
          "ops": [
            "values"
          ],
          "fields": [
            "target"
          ],
          "as": [
            "connections"
          ]
        },
        {
          "type": "formula",
          "as": "targets",
          "expr": "pluck(datum.connections, 'target')"
        }
      ]
    },
    {
      "name": "target-connections",
      "source": "link-data-raw",
      "transform": [
        {
          "type": "aggregate",
          "groupby": [
            "target"
          ],
          "ops": [
            "values"
          ],
          "fields": [
            "source"
          ],
          "as": [
            "connections"
          ]
        },
        {
          "type": "formula",
          "as": "sources",
          "expr": "pluck(datum.connections, 'source')"
        }
      ]
    },
    {
      "name": "node-data",
      "source": "node-data-raw",
      "transform": [
        {
          "type": "lookup",
          "from": "source-connections",
          "key": "source",
          "fields": [
            "name"
          ],
          "values": [
            "targets"
          ],
          "as": [
            "targets"
          ],
          "default": [
            ""
          ]
        },
        {
          "type": "lookup",
          "from": "target-connections",
          "key": "target",
          "fields": [
            "name"
          ],
          "values": [
            "sources"
          ],
          "as": [
            "sources"
          ],
          "default": [
            ""
          ]
        },
        {
          "type": "force",
          "iterations": 300,
          "restart": {
            "signal": "restart"
          },
          "signal": "force",
          "forces": [
            {
              "force": "center",
              "x": {
                "signal": "cx"
              },
              "y": {
                "signal": "cy"
              }
            },
            {
              "force": "collide",
              "radius": {
                "signal": "sqrt(4 * nodeRadius * nodeRadius)"
              },
              "iterations": 1,
              "strength": 0.7
            },
            {
              "force": "nbody",
              "strength": {
                "signal": "nodeCharge"
              }
            },
            {
              "force": "link",
              "links": "link-data-raw",
              "distance": {
                "signal": "linkDistance"
              },
              "id": "name"
            }
          ]
        },
        {
          "type": "formula",
          "as": "fx",
          "expr": "fix[0]!=null && node==datum.index ?invert('xscale',fix[0]):null"
        },
        {
          "type": "formula",
          "as": "fy",
          "expr": "fix[1]!=null && node==datum.index ?invert('yscale',fix[1]):null"
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "color",
      "type": "ordinal",
      "domain": {
        "data": "node-data",
        "field": "group"
      },
      "range": [
        "#4682b4",
        "#4666b4",
        "#46b494",
        "#b46746",
        "#b44662",
        "#a44fa3"
      ]
    },
    {
      "name": "xscale",
      "zero": false,
      "domain": {
        "signal": "xdom"
      },
      "range": {
        "signal": "xrange"
      }
    },
    {
      "name": "yscale",
      "zero": false,
      "domain": {
        "signal": "ydom"
      },
      "range": {
        "signal": "yrange"
      }
    }
  ],
  "marks": [
    {
      "type": "path",
      "name": "links",
      "from": {
        "data": "link-data"
      },
      "interactive": false,
      "encode": {
        "update": {
          "stroke": {
            "signal": "datum.source.index!=nodeHover.id && datum.target.index!=nodeHover.id ? '#929399':merge(hsl(scale('color', datum.source.group)), {l:0.64})"
          },
          "strokeWidth": {
            "signal": "datum.source.index!=nodeHover.id && datum.target.index!=nodeHover.id ? 0.5:2"
          }
        }
      },
      "transform": [
        {
          "type": "linkpath",
          "require": {
            "signal": "force"
          },
          "shape": "line",
          "sourceX": {
            "expr": "scale('xscale', datum.datum.source.x)"
          },
          "sourceY": {
            "expr": "scale('yscale', datum.datum.source.y)"
          },
          "targetX": {
            "expr": "scale('xscale', datum.datum.target.x)"
          },
          "targetY": {
            "expr": "scale('yscale', datum.datum.target.y)"
          }
        },
        {
          "type": "formula",
          "expr": "atan2(datum.datum.target.y - datum.datum.source.y,datum.datum.source.x - datum.datum.target.x)",
          "as": "angle1"
        },
        {
          "type": "formula",
          "expr": "(datum.angle1>=0?datum.angle1:(2*PI + datum.angle1)) * (360 / (2*PI))",
          "as": "angle2"
        },
        {
          "type": "formula",
          "expr": "(360-datum.angle2)*(PI/180)",
          "as": "angle3"
        },
        {
          "type": "formula",
          "expr": "(cos(datum.angle3)*(nodeRadius+5))+(scale('xscale',datum.datum.target.x))",
          "as": "arrowX"
        },
        {
          "type": "formula",
          "expr": "(sin(datum.angle3)*(nodeRadius+5))+(scale('yscale',datum.datum.target.y))",
          "as": "arrowY"
        }
      ]
    },
    {
      "type": "symbol",
      "name": "arrows",
      "zindex": 1,
      "from": {
        "data": "links"
      },
      "encode": {
        "update": {
          "shape": {
            "value": "triangle"
          },
          "angle": {
            "signal": "-datum.angle2-90"
          },
          "x": {
            "signal": "datum.arrowX"
          },
          "y": {
            "signal": "datum.arrowY"
          },
          "text": {
            "signal": "'▲'"
          },
          "fill": {
            "signal": "datum.datum.source.index!=nodeHover.id && datum.datum.target.index!=nodeHover.id ? '#929399':merge(hsl(scale('color', datum.datum.source.group)), {l:0.64})"
          },
          "size": {
            "signal": "nodeRadius==1?0:60"
          }
        }
      }
    },
    {
      "name": "nodes",
      "type": "symbol",
      "zindex": 1,
      "from": {
        "data": "node-data"
      },
      "encode": {
        "update": {
          "opacity": {
            "value": 1
          },
          "href": {
            "signal": "datum.link"
          },
          "fill": {
            "signal": "nodeHover.id===datum.index || indexof(nodeHover.connections, datum.name)>-1 ?scale('color', datum.group):merge(hsl(scale('color', datum.group)), {l:0.64})"
          },
          "stroke": {
            "signal": "nodeHover.id===datum.index || indexof(nodeHover.connections, datum.name)>-1 ?scale('color', datum.group):merge(hsl(scale('color', datum.group)), {l:0.84})"
          },
          "strokeWidth": {
            "value": 3
          },
          "strokeOpacity": {
            "value": 1
          },
          "size": {
            "signal": "4 * nodeRadius * nodeRadius"
          },
          "cursor": {
            "value": "pointer"
          },
          "x": {
            "signal": "fix[0]!=null && node===datum.index ?fix[0]:scale('xscale', datum.x)"
          },
          "y": {
            "signal": "fix[1]!=null && node===datum.index ?fix[1]:scale('yscale', datum.y)"
          }
        },
        "hover": {
          "tooltip": {
            "signal": "datum.name"
          }
        }
      }
    },
    {
      "type": "text",
      "name": "labels",
      "from": {
        "data": "nodes"
      },
      "zindex": 2,
      "interactive": false,
      "enter": {},
      "encode": {
        "update": {
          "fill": {
            "signal": "'white'"
          },
          "y": {
            "field": "y"
          },
          "x": {
            "field": "x"
          },
          "text": {
            "field": "datum.name"
          },
          "align": {
            "value": "center"
          },
          "fontSize": {
            "value": 10
          },
          "baseline": {
            "value": "middle"
          },
          "limit": {
            "signal": "clamp(sqrt(4 * nodeRadius * nodeRadius)-7,1,1000)"
          },
          "ellipsis": {
            "value": " "
          }
        }
      }
    }
  ]
}"}}

{"title":"Disk I/O Operations","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
