                },
                {"value": 0}
              ],
              "y": [
                {
                  "test": "data(\"param_37_store\").length && data(\"param_37_store\")[0].unit === \"view_50\"",
                  "value": 0
                },
                {"value": 0}
              ],
              "x2": [
                {
                  "test": "data(\"param_37_store\").length && data(\"param_37_store\")[0].unit === \"view_50\"",
                  "signal": "param_37_x[1]"
                },
                {"value": 0}
              ],
              "y2": [
                {
                  "test": "data(\"param_37_store\").length && data(\"param_37_store\")[0].unit === \"view_50\"",
                  "field": {"group": "height"}
                },
                {"value": 0}
              ],
              "stroke": [
                {"test": "param_37_x[0] !== param_37_x[1]", "value": "white"},
                {"value": null}
              ]
            }
          }
        }
      ],
      "axes": [
        {
          "scale": "view_50_x",
          "orient": "bottom",
          "gridScale": "view_50_y",
          "grid": true,
          "tickCount": {"signal": "ceil(width/40)"},
          "domain": false,
          "labels": false,
          "aria": false,
          "maxExtent": 0,
          "minExtent": 0,
          "ticks": false,
          "zindex": 0
        },
        {
          "scale": "view_50_y",
          "orient": "left",
          "gridScale": "view_50_x",
          "grid": true,
          "tickCount": {"signal": "ceil(view_50_height/40)"},
          "domain": false,
          "labels": false,
          "aria": false,
          "maxExtent": 0,
          "minExtent": 0,
          "ticks": false,
          "zindex": 0
        },
        {
          "scale": "view_50_x",
          "orient": "bottom",
          "grid": false,
          "title": "Time",
          "labelFlush": true,
          "labelOverlap": true,
          "tickCount": {"signal": "ceil(width/40)"},
          "zindex": 0
        },
        {
          "scale": "view_50_y",
          "orient": "left",
          "grid": false,
          "title": "Average Metric Value",
          "labelOverlap": true,
          "tickCount": {"signal": "ceil(view_50_height/40)"},
