{"title":"Docker Container State Summary","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "title": "Docker Container State Summary",
  "padding": 5,
  "data": [
    {
      "name": "states",
      "url": {
        "index": "metricbeat-*",
        "body": {
          "size": 0,
          "query": {
            "term": {
              "metricset.name.keyword": "container"
            }
          },
          "aggs": {
            "running": {
              "filter": {
                "wildcard": {
                  "docker.container.status.keyword": "Up*"
                }
              },
              "aggs": {
                "containers": {
                  "cardinality": {
                    "field": "container.name.keyword"
                  }
                }
              }
            },
            "paused": {
              "filter": {
                "wildcard": {
                  "docker.container.status.keyword": "*Paused*"
                }
              },
              "aggs": {
                "containers": {
                  "cardinality": {
                    "field": "container.name.keyword"
                  }
                }
              }
            },
            "stopped": {
              "filter": {
                "bool": {
                  "must_not": [
                    {
                      "wildcard": {
                        "docker.container.status.keyword": "Up*"
                      }
                    }
                  ]
                }
              },
              "aggs": {
                "containers": {
                  "cardinality": {
                    "field": "container.name.keyword"
                  }
                }
              }
            }
          }
        }
      },
      "format": {
        "property": "aggregations"
      },
      "transform": [
        {
          "type": "formula",
          "as": "running",
          "expr": "datum.running.containers.value"
        },
        {
          "type": "formula",
          "as": "paused",
          "expr": "datum.paused.containers.value"
        },
        {
          "type": "formula",
          "as": "stopped",
          "expr": "datum.stopped.containers.value"
        },
        {
          "type": "fold",
          "fields": [
            "running",
            "paused",
            "stopped"
          ],
          "as": [
            "state",
            "count"
          ]
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "x",
      "type": "band",
      "domain": {
        "data": "states",
        "field": "state"
      },
      "range": "width",
      "padding": 0.25
    },
    {
      "name": "color",
      "type": "ordinal",
      "domain": [
        "running",
        "paused",
        "stopped"
      ],
      "range": [
        "#54b399",
        "#d6bf57",
        "#e7664c"
      ]
    }
  ],
  "marks": [
    {
      "type": "text",
      "from": {
        "data": "states"
      },
      "encode": {
        "update": {
          "x": {
            "scale": "x",
            "field": "state",
            "band": 0.5
          },
          "y": {
            "value": 35
          },
          "text": {
            "field": "count"
          },
          "fontSize": {
            "value": 38
          },
          "fontWeight": {
            "value": "bold"
          },
          "align": {
            "value": "center"
          },
          "fill": {
            "scale": "color",
            "field": "state"
          }
        }
      }
    },
    {
      "type": "text",
      "from": {
        "data": "states"
      },
      "encode": {
        "update": {
          "x": {
            "scale": "x",
            "field": "state",
            "band": 0.5
          },
          "y": {
            "value": 75
          },
          "text": {
            "field": "state"
          },
          "fontSize": {
            "value": 13
          },
          "align": {
