        {
          "type": "formula",
          "as": "container",
          "expr": "datum.key"
        },
        {
          "type": "formula",
          "as": "time",
          "expr": "toDate(datum.bucket.key)"
        },
        {
          "type": "formula",
          "as": "in_value",
          "expr": "isValid(datum.bucket.in.value) ? datum.bucket.in.value : null"
        },
        {
          "type": "formula",
          "as": "out_value",
          "expr": "isValid(datum.bucket.out.value) ? datum.bucket.out.value : null"
        },
        {
          "type": "fold",
          "fields": [
            "in_value",
            "out_value"
          ],
          "as": [
            "metric",
            "value"
          ]
        },
        {
          "type": "formula",
          "as": "metric_name",
          "expr": "replace(datum.metric, '_value', '')"
        },
        {
          "type": "formula",
          "as": "series",
          "expr": "datum.container + ' / ' + datum.metric_name"
        },
        {
          "type": "filter",
          "expr": "datum.value != null && isValid(datum.value)"
        },
        {
          "type": "formula",
          "as": "scaled",
          "expr": "datum.value / 1048576"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "series",
              "time"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "x",
      "type": "time",
      "domain": {
        "data": "flat",
        "field": "time"
      },
      "range": "width",
      "nice": true
    },
    {
      "name": "y",
      "type": "linear",
      "domain": {
        "data": "flat",
        "field": "scaled"
      },
      "range": "height",
      "nice": true,
      "zero": true
    },
    {
      "name": "color",
      "type": "ordinal",
      "domain": {
        "data": "flat",
        "field": "series"
      },
      "range": "category"
    }
  ],
  "axes": [
    {
      "orient": "bottom",
      "scale": "x",
      "title": null,
      "labelOverlap": true
    },
    {
      "orient": "left",
      "scale": "y",
      "title": "MB"
    }
  ],
  "legends": [
    {
      "fill": "color",
      "orient": "bottom",
      "title": null,
      "labelLimit": 180,
      "columns": 3
    }
  ],
  "marks": [
    {
      "type": "group",
      "from": {
        "facet": {
          "name": "series",
          "data": "flat",
          "groupby": "series"
        }
      },
      "marks": [
        {
          "type": "area",
          "from": {
            "data": "series"
          },
          "encode": {
            "enter": {
              "strokeWidth": {
                "value": 1
              },
              "fillOpacity": {
                "value": 0.28
              },
              "interpolate": {
                "value": "monotone"
              }
            },
            "update": {
              "x": {
                "scale": "x",
                "field": "time"
              },
              "y": {
                "scale": "y",
                "field": "scaled"
              },
              "y2": {
                "scale": "y",
                "value": 0
              },
              "stroke": {
                "scale": "color",
                "field": "series"
              },
              "fill": {
                "scale": "color",
                "field": "series"
              },
              "tooltip": {
                "signal": "{'series': datum.series, 'time': timeFormat(datum.time, '%H:%M:%S'), 'value': format(datum.scaled, '.2f')}"
              }
            }
          }
        }
      ]
    }
  ]
}"}}

