{"title":"OTel Metrics by Service","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "title": "OTel Metrics by Service",
  "padding": 5,
  "autosize": {
    "type": "fit",
    "contains": "padding"
  },
  "data": [
    {
      "name": "rawdata",
      "url": {
        "index": "otel-metrics-*",
        "%context%": true,
        "%timefield%": "time",
        "body": {
          "size": 0,
          "aggs": {
            "values_only": {
              "filter": {
                "exists": {
                  "field": "value"
                }
              },
              "aggs": {
                "services": {
                  "terms": {
                    "field": "serviceName.keyword",
                    "size": 6,
                    "order": {
                      "_count": "desc"
                    },
                    "missing": "unknown"
                  },
                  "aggs": {
                    "metrics": {
                      "terms": {
                        "field": "name.keyword",
                        "size": 4,
                        "order": {
                          "_count": "desc"
                        }
                      },
                      "aggs": {
                        "time_buckets": {
                          "date_histogram": {
                            "field": "time",
                            "fixed_interval": "30m",
                            "extended_bounds": {
                              "min": {
                                "%timefilter%": "min"
                              },
                              "max": {
                                "%timefilter%": "max"
                              }
                            },
                            "min_doc_count": 0
                          },
                          "aggs": {
                            "avg_value": {
                              "avg": {
                                "field": "value"
                              }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      },
      "format": {
        "property": "aggregations.values_only.services.buckets"
      }
    },
    {
      "name": "metricdata",
      "source": "rawdata",
      "transform": [
        {
          "type": "flatten",
          "fields": [
            "metrics.buckets"
          ],
          "as": [
            "metric"
          ]
        }
      ]
    },
    {
      "name": "flatdata",
      "source": "metricdata",
      "transform": [
        {
          "type": "flatten",
          "fields": [
            "metric.time_buckets.buckets"
          ],
          "as": [
            "bucket"
          ]
        },
        {
          "type": "formula",
          "as": "service",
          "expr": "datum.key"
        },
        {
          "type": "formula",
          "as": "metric_name",
          "expr": "datum.metric.key"
        },
        {
          "type": "formula",
          "as": "series",
          "expr": "datum.key + ' / ' + datum.metric.key"
        },
        {
          "type": "formula",
          "as": "time",
          "expr": "toDate(datum.bucket.key)"
        },
        {
          "type": "formula",
          "as": "value",
          "expr": "isValid(datum.bucket.avg_value.value) ? datum.bucket.avg_value.value : null"
        },
        {
          "type": "filter",
          "expr": "datum.value != null"
        },
        {
          "type": "collect",
          "sort": {
            "field": [
              "series",
              "time"
            ],
            "order": [
              "ascending",
              "ascending"
            ]
          }
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "x",
      "type": "time",
      "domain": {
        "data": "flatdata",
        "field": "time"
      },
      "range": "width",
      "nice": true
    },
    {
      "name": "y",
      "type": "linear",
      "domain": {
        "data": "flatdata",
        "field": "value"
      },
      "range": "height",
      "nice": true,
      "zero": true
    },
    {
      "name": "color",
      "type": "ordinal",
      "domain": {
        "data": "flatdata",
        "field": "series"
      },
      "range": "category"
    }
  ],
  "axes": [
    {
      "orient": "bottom",
      "scale": "x",
      "format": "%H:%M",
      "labelOverlap": true,
      "title": "time"
    },
    {
      "orient": "left",
      "scale": "y",
      "labelOverlap": true,
      "title": "avg(value)"
    }
  ],
  "legends": [
    {
      "fill": "color",
      "orient": "right",
      "title": "service / metric",
      "labelLimit": 360,
      "symbolSize": 80
    }
  ],
  "marks": [
    {
      "type": "group",
      "from": {
        "facet": {
          "name": "series_facet",
          "data": "flatdata",
          "groupby": "series"
        }
      },
      "marks": [
        {
          "type": "line",
          "from": {
            "data": "series_facet"
          },
          "encode": {
            "enter": {
              "strokeWidth": {
                "value": 2
              }
            },
            "update": {
              "x": {
                "scale": "x",
                "field": "time"
              },
              "y": {
                "scale": "y",
                "field": "value"
              },
              "stroke": {
                "scale": "color",
                "field": "series"
              }
            }
          }
        }
      ]
    }
  ]
}"}}

{"title":"OTEL - signal volume by index","type":"vega","aggs":[],"params":{"spec":"{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "title": "OTEL signal volume by index",
  "padding": 5,
  "data": [
    {
      "name": "indices",
      "url": {
        "index": "otel-events*,otel-metrics*,otel-v1-apm-span-*",
        "%context%": true,
        "body": {
          "size": 0,
          "aggs": {
            "indices": {
              "terms": {
                "field": "_index",
                "size": 80,
                "order": {
                  "_count": "desc"
                }
              }
            }
          }
        }
      },
      "format": {
        "property": "aggregations.indices.buckets"
      },
      "transform": [
        {
          "type": "formula",
          "as": "signal",
          "expr": "indexof(datum.key, 'otel-events') == 0 ? 'events' : indexof(datum.key, 'otel-metrics') == 0 ? 'metrics' : 'spans'"
        },
        {
          "type": "aggregate",
          "groupby": [
            "signal"
          ],
          "fields": [
            "doc_count"
          ],
          "ops": [
            "sum"
          ],
          "as": [
            "docs"
          ]
        }
      ]
    }
  ],
  "scales": [
    {
      "name": "x",
      "type": "band",
      "domain": {
        "data": "indices",
        "field": "signal"
      },
      "range": "width",
      "padding": 0.25
    },
    {
      "name": "y",
      "type": "linear",
      "domain": {
        "data": "indices",
        "field": "docs"
      },
      "range": "height",
      "nice": true,
      "zero": true
    },
    {
      "name": "color",
      "type": "ordinal",
      "domain": [
        "events",
        "metrics",
        "spans"
      ],
      "range": [
        "#54b399",
        "#6092c0",
        "#d36086"
      ]
    }
  ],
  "axes": [
    {
      "orient": "bottom",
      "scale": "x",
      "title": null
    },
    {
      "orient": "left",
      "scale": "y",
      "title": "documents"
    }
  ],
  "marks": [
    {
      "type": "rect",
      "from": {
        "data": "indices"
      },
      "encode": {
        "update": {
          "x": {
            "scale": "x",
            "field": "signal"
          },
          "width": {
            "scale": "x",
            "band": 1
          },
          "y": {
            "scale": "y",
            "field": "docs"
          },
          "y2": {
            "scale": "y",
            "value": 0
          },
          "fill": {
            "scale": "color",
            "field": "signal"
          },
          "tooltip": {
            "signal": "{'signal': datum.signal, 'documents': datum.docs}"
          }
        }
      }
    },
    {
      "type": "text",
      "from": {
        "data": "indices"
      },
      "encode": {
        "update": {
          "x": {
            "scale": "x",
            "field": "signal",
            "band": 0.5
          },
          "y": {
            "scale": "y",
            "field": "docs",
            "offset": -6
          },
          "align": {
            "value": "center"
          },
          "baseline": {
            "value": "bottom"
          },
          "text": {
            "signal": "format(datum.docs, ',')"
          },
          "fill": {
            "value": "#343741"
          }
        }
      }
    }
  ]
}"}}
